import { Hono } from 'hono';
import { chatRoutes } from './chat';

/**
 * The Tabula backend. All routes live under /api (the basePath).
 * This single `app` is mounted into the Astro worker via
 * src/pages/api/[...path].ts — no separate deploy.
 *
 * `Bindings` is the global ambient `Env` generated by `wrangler types`
 * (run `pnpm generate-types` after editing bindings in wrangler.jsonc).
 * Add R2 / D1 / AI bindings there and they become available as `c.env.*`.
 */
export const app = new Hono<{ Bindings: Env }>().basePath('/api');

app.get('/ping', (c) => c.json({ ok: true, service: 'tabula-api' }));

// AI chat — natural language → structured data query (MVP #4).
app.route('/chat', chatRoutes);

// Mount more feature routers here as you build them, e.g.
// app.route('/upload', uploadRoutes);
// app.route('/diff', diffRoutes);

export type AppType = typeof app;
